head.script:
// 전역 변수
scwin.memJson = $c.data.getMemInfo();
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;
scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd;
scwin.vCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.isSubCompany = false;
scwin.privAdmin = scwin.memJson.privAdmin;
scwin.txtCoClsCd = "";

scwin.isStart = false;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
	$c.gus.cfDisableKey();

    const codeOptions = [
        { grpCd : "CO001", compID : "lc_srchCntlUnitClsCd,gr_master:cntlUnitClsCd" }, // 셀렉트
        { grpCd : "FI042", compID : "lc_costClsCd" },
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.ondataload = function(){
    let cnt = dlt_commonCodeCO001.getRowCount();
    for (let i = 0; i < cnt; i++){
        let cdNm = dlt_commonCodeCO001.getCellData(i, "cdNm")
        if (cdNm == ""){
            dlt_commonCodeCO001.removeRow(i)
        }
    }
}

/**
 * UDC값
 */
scwin.onUdcCompleted = function() {
    scwin.f_FieldClear();
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search);
    scwin.f_SetSrchDefault();
};

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function() {
    $c.gus.cfInitHidVal(tbl_search);
    ed_srchBudgetYm.setValue($c.date.getServerDateTime("yyyy")+"01");
    ed_srchBudgetYmTo.setValue($c.date.getServerDateTime("yyyyMM"));
    ed_srchBudgetYm.focus();
};

//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    let ret = await $c.gus.cfValidate([ed_coCd, ed_srchBudgetYm, ed_srchBudgetYmTo, ed_srchAcctDeptCd]);
    if (!ret) {
        return false;
    }

    if (ed_srchBudgetYm.getValue().substring(0, 4) != ed_srchBudgetYmTo.getValue().substring(0, 4)) {
        await $c.win.alert("조회기간의 년도가 다릅니다.");
        ed_srchBudgetYm.focus();
        return;
    }

    if (!$c.gus.cfIsAfterDate(ed_srchBudgetYm.getValue() + "01", ed_srchBudgetYmTo.getValue() + "01")) {
        await $c.win.alert("예산년월의 범위가 잘못되었습니다.");
        ed_srchBudgetYm.focus();
        return;
    }

    let ret2 = await $c.gus.cfValidate([ed_srchAcctDeptCd]);
    if (!ret2) {
        return false;
    }

    $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    scwin.isStart = true;
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    await udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc
										,ed_coCd.getValue(), ""
										,pWinCloseTF,null,null,null,null
										,null,null,null,null,null);   
};

scwin.udc_dongbuGroupCompanyInfo_callBackFunc = function(rtnList) {
    //SET
    if (rtnList !== null) {
        if (rtnList[0] == "N/A") return;

        ed_coCd.setValue(rtnList[0]);
        ed_coNm.setValue(rtnList[5]);
        scwin.txtCoClsCd=rtnList[1];

    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        scwin.txtCoClsCd="";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if(scwin.isStart == true) {
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) {
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }
    }
    scwin.isStart = false;
};

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_PopUp = async function(paramArray,pAllSearchTF) {
    let code = ($c.gus.cfIsNull(paramArray.pCode) ? "" : $c.gus.cfGetValue(paramArray.pCode));
    await udc_budgetCtrlDeptInfo.cfCommonPopUp(scwin.udc_budgetCtrlDeptInfo_callBackFunc, code, ""
							   		,pAllSearchTF, paramArray.pDispCnt
							   		,paramArray.pTitle, paramArray.pWidth
							   		,paramArray.pHidden, paramArray.pWhere
							   		,paramArray.pW, paramArray.pH
							   		,paramArray.pTop, paramArray.pLeft
							   		,paramArray.pExistTF, paramArray.pAllSearchTF
							   		,paramArray.pWtitleSearch)
};

scwin.udc_budgetCtrlDeptInfo_callBackFunc = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_srchAcctDeptCd, ed_srchAcctDeptNm);
    if (rtnList != null && rtnList[0] != "N/A") {
        lc_costClsCd.setValue(rtnList[2]);
    }
};

//-------------------------------------------------------------------------
// 부서코드팝업
//-------------------------------------------------------------------------
scwin.f_deptPopUp = async function(pAllSearchTF) {
    let codeObj = ed_srchAcctDeptCd;
    let nameObj = ed_srchAcctDeptNm;
    let paramArray = {};

    paramArray.pSelectID = "retrieveBudgetCtrlDeptInfo";
    paramArray.pCode = codeObj;
    paramArray.pName = nameObj;
    paramArray.pW = "410";
    paramArray.pAllSearchTF = 'T';
    paramArray.pWhere = ",," + ed_coCd.getValue();

    await scwin.f_PopUp(paramArray,pAllSearchTF);
};



//-------------------------------------------							
// 그리드 데이터 엑셀로 다운							
//-------------------------------------------	
scwin.f_runExcel = async function() {
    let totCnt = ds_master.getRowCount();
    let sheetTitle = "예산배정내역";

    if (totCnt != 0) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            $c.data.downloadGridViewExcel(gr_master, { fileName: sheetTitle + ".xlsx", sheetName: sheetTitle });
        }
    } else {
        await $c.win.alert(MSG_CM_WRN_002);
    }
};

//-------------------------------------------							
// 그리드 높이 늘리고 줄이기							
//-------------------------------------------							
scwin.f_grdHeiht = function(gridNm, size) {
    let strHeight = gridNm.getHeight();
    let intHeight = parseInt(strHeight.replace("px", ""));
    intHeight = intHeight + size;
    if (intHeight > 0) {
        gridNm.setHeight(intHeight + "px");
    }
};

scwin.udc_dongbuGroupCompanyInfo_onclickEvent = async function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

scwin.udc_budgetCtrlDeptInfo_onclickEvent = async function (e) {
    scwin.f_deptPopUp('T');
};

scwin.sbm_search_submitdone = async function (e) {
    totalRows.setValue(ds_master.getRowCount());
    if(ds_master.getRowCount() == 0) {
        if($c.gus.cfCheckCreateFlag() == true){
	    	$c.gus.cfTurnCreateFlag(false);
	   }else{
			await $c.win.alert(MSG_CM_WRN_002);
	   }
	} else {
		gr_master.focus();
	}
};

scwin.udc_budgetCtrlDeptInfo_onblurCodeEvent = function (e) {
    if (ed_srchAcctDeptCd.getValue() != ""){
        scwin.f_deptPopUp('T');
    }
    else{
        ed_srchAcctDeptNm.setValue("");
    }
};

scwin.udc_dongbuGroupCompanyInfo_onblurCodeEvent = function (e) {
    if (ed_coCd.getValue() != ""){
        scwin.f_PopUpCompanyInfo('T');
    }
    else{
        ed_coNm.setValue("");
    }
};
